import { create } from "zustand";

const useCartStore = create((set) => ({
  cart: [
    { id: 1, imgurl: "fruit1.jpg", name: "수박", count: 2 },
    { id: 2, imgurl: "fruit2.jpg", name: "참외", count: 1 },
    { id: 3, imgurl: "fruit3.jpg", name: "사과", count: 1 },
  ],

  // 수량 1 증가
  addCount: (id) =>
    set((state) => ({
      cart: state.cart.map((item) =>
        item.id === id ? { ...item, count: item.count + 1 } : item
      ),
    })),

  // 수량 1 감소 (0 이하면 알림)
  decreaseCount: (id) =>
    set((state) => ({
      cart: state.cart.map((item) => {
        if (item.id !== id) return item;
        if (item.count === 0) {
          alert("상품이 더 이상 없습니다.");
          return item;
        }
        return { ...item, count: item.count - 1 };
      }),
    })),

  // 상품 추가 (이미 있으면 수량 +1)
  addItem: (newItem) =>
    set((state) => {
      const exists = state.cart.find((item) => item.id === newItem.id);
      if (exists) {
        return {
          cart: state.cart.map((item) =>
            item.id === newItem.id ? { ...item, count: item.count + 1 } : item
          ),
        };
      }
      return { cart: [...state.cart, newItem] };
    }),

  // 상품 삭제
  deleteItem: (id) =>
    set((state) => ({
      cart: state.cart.filter((item) => item.id !== id),
    })),

  // 이름순 정렬
  sortName: () =>
    set((state) => ({
      cart: [...state.cart].sort((a, b) => (a.name > b.name ? 1 : -1)),
    })),
}));

export default useCartStore;
