import "./App.css";
import { Button, Navbar, Container, Nav } from "react-bootstrap";

import Products from "./components/Products";
import { Routes, Route, useNavigate } from "react-router-dom";
import Detail from "./components/Detail";
import NotFound from "./components/NotFound";
import About from "./components/About";
import Member from "./components/Member";
import Location from "./components/Loacation";
import Title from "./components/Title";
import Title2 from "./components/Title2";
import ComVeggie from "./components/ComVeggie";
import Footer from "./components/Footer";
import useFruitStore from "./store/useFruitStore";
import useVeggieQuery from "./hooks/useVeggieQuery";
import Cart from "./components/Cart";

function App() {
  let navigate = useNavigate();

  const fruits = useFruitStore((state) => state.fruits);
  const veggies = useFruitStore((state) => state.veggies);
  const sortByName = useFruitStore((state) => state.sortByName);
  const sortByPriceLowToHigh = useFruitStore(
    (state) => state.sortByPriceLowToHigh,
  );
  const sortByPriceHighToLow = useFruitStore(
    (state) => state.sortByPriceHighToLow,
  );
  const { loadMore, isFetching } = useVeggieQuery();

  return (
    <div className="App">
      <>
        <Navbar bg="dark" variant="dark">
          <Container>
            <Navbar.Brand
              onClick={() => {
                navigate("/");
              }}
            >
              과일농장
            </Navbar.Brand>
            <Nav className="me-auto">
              <Nav.Link
                onClick={() => {
                  navigate("/");
                }}
              >
                홈으로
              </Nav.Link>
              <Nav.Link
                onClick={() => {
                  navigate("/detail/1");
                }}
              >
                상세페이지
              </Nav.Link>
              <Nav.Link
                onClick={() => {
                  navigate("/cart");
                }}
              >
                장바구니
              </Nav.Link>
              <Nav.Link
                onClick={() => {
                  navigate("/about");
                }}
              >
                회사소개
              </Nav.Link>
            </Nav>
          </Container>
        </Navbar>
      </>

      <Routes>
        <Route
          path="/"
          element={
            <div>
              <div
                className="slider"
                style={{
                  backgroundImage: `url(${process.env.PUBLIC_URL + "/img/slider.jpg"})`,
                }}
              ></div>
              <Title />
              <div class="container">
                <div class="row">
                  <div style={{ textAlign: "center" }}>
                    <Button
                      className="me-2"
                      variant="outline-primary"
                      onClick={sortByName}
                    >
                      이름순 정렬
                    </Button>
                    <Button
                      className="me-2"
                      variant="outline-secondary"
                      onClick={sortByPriceLowToHigh}
                    >
                      낮은가격순 정렬
                    </Button>{" "}
                    <Button
                      variant="outline-success"
                      onClick={sortByPriceHighToLow}
                    >
                      높은가격순 정렬
                    </Button>
                  </div>
                </div>
              </div>
              <div className="container" style={{ marginTop: "30px" }}>
                <div className="row">
                  {fruits.map((fruit) => (
                    <Products {...fruit} key={fruit.id} />
                  ))}
                </div>
              </div>
              <div class="container">
                <div class="row">
                  <div style={{ textAlign: "center" }}>
                    <Title2 />
                    <Button
                      variant="outline-success"
                      onClick={loadMore}
                      disabled={isFetching}
                    >
                      {isFetching ? "로딩중..." : "+ 3개 상품 더 보기"}
                    </Button>{" "}
                  </div>
                </div>
              </div>
              <div className="container mt-3">
                <div className="row">
                  {veggies.map((item) => (
                    <ComVeggie {...item} key={item.id} />
                  ))}{" "}
                </div>
              </div>
              <Footer />
            </div>
          }
        />

        <Route path="/detail/:paramId" element={<Detail />} />
        <Route path="/cart" element={<Cart />} />

        <Route path="/about" element={<About />}>
          <Route path="member" element={<Member />} />
          <Route path="location" element={<Location />} />
        </Route>

        <Route path="*" element={<NotFound />} />
      </Routes>
    </div>
  );
}

export default App;
