import { create } from "zustand";
import data from "../db/fruit";
import data2 from "../db/veggie";

const useFruitStore = create((set) => ({
  fruits: data,
  veggies: data2,
  count: 1,

  sortByName: () => {
    set((state) => ({
      fruits: [...state.fruits].sort((a, b) => (a.title > b.title ? 1 : -1)),
    }));
  },

  sortByPriceLowToHigh: () => {
    set((state) => ({
      fruits: [...state.fruits].sort((a, b) => a.price - b.price),
    }));
  },

  sortByPriceHighToLow: () => {
    set((state) => ({
      fruits: [...state.fruits].sort((a, b) => b.price - a.price),
    }));
  },

  addVeggies: (newVeggies) => {
    set((state) => ({
      veggies: [...state.veggies, ...newVeggies],
      count: state.count + 1,
    }));
  },
}));

export default useFruitStore;
