import { useQuery } from "@tanstack/react-query";
import axios from "axios";
import useFruitStore from "../store/useFruitStore";

const VEGGIE_URLS = {
  1: "https://sinaboro.github.io/react_data/veggie2.json",
  2: "https://sinaboro.github.io/react_data/veggie3.json",
};

const useVeggieQuery = () => {
  const count = useFruitStore((state) => state.count);
  const addVeggies = useFruitStore((state) => state.addVeggies);

  const { refetch, isFetching } = useQuery({
    queryKey: ["veggies", count],
    queryFn: async () => {
      const { data } = await axios.get(VEGGIE_URLS[count]);
      return data;
    },
    enabled: false,
  });

  const loadMore = async () => {
    if (count > 2) {
      alert("더이상 상품이 없습니다.");
      return;
    }
    const result = await refetch();
    if (result.data) {
      addVeggies(result.data);
    }
  };

  return { loadMore, isFetching };
};

export default useVeggieQuery;
